class TrieNode:
    def __init__(self):
        self.children = {}

class Solution:
    def insert(self, node: TrieNode, ch: str) -> bool:
        if not node:
            node = TrieNode()
            node.children[ch] = TrieNode()
            return True
        return ch in node.children

    def delete(self, node: TrieNode, ch: str) -> bool:
        if not node:
            return False
        if ch in node.children:
            del node.children[ch]
            return len(node.children) == 0
        return False

n = int(input())
for _ in range(n):
    op, ch = input().split()
    if op == 'insert':
        print(Solution().insert(TrieNode(), ch))
    else:
        print(Solution().delete(TrieNode(), ch))

solutions.cpp:
#include <bits/stdc++.h>

using namespace std;

class TrieNode {
public:
    unordered_map<char, TrieNode*> children;
};

class Solution {
public:
    bool insert(TrieNode* node, char ch) {
        if (!node) {
            node = new TrieNode();
            node->children[ch-'a'] = new TrieNode();
            return true;
        }
        return node->children.find(ch-'a') != node->children.end();
    }

    bool delete(TrieNode* node, char ch) {
        if (!node) {
            return false;
        }
        if (node->children.find(ch-'a') != node->children.end()) {
            node->children.erase(ch-'a');
            return node->children.size() == 0;
        }
        return false;
    }
};

int main() {
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        string op, ch;
        cin >> op >> ch;
        if (op == "insert") {
            cout << Solution().insert(new TrieNode(), ch[0]) << endl;
        } else {
            cout << Solution().delete(new TrieNode(), ch[0]) << endl;
        }
    }
    return 0;
}
